import{_ as a,o as e,c as d,a3 as r}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"模块总览","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/index.md","filePath":"cosmos/framework/packages/index.md","lastUpdated":1783216089000}'),i={name:"cosmos/framework/packages/index.md"};function n(o,t,s,h,l,c){return e(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="模块总览" tabindex="-1">模块总览 <a class="header-anchor" href="#模块总览" aria-label="Permalink to &quot;模块总览&quot;">​</a></h1><p>XiHan.Framework 由 <strong>57 个 NuGet 包</strong>组成，按分层组织。每个包都有独立文档——下面的表格按层分组，点击即可查阅。</p><blockquote><p>命名约定：<code>XiHan.Framework.[模块名]</code> 为通用类库，<code>XiHan.Framework.Web.[模块名]</code> 为 Web 功能。安装即 <code>dotnet add package &lt;包名&gt;</code>。</p></blockquote><h2 id="如何选择要装哪些包" tabindex="-1">如何选择要装哪些包 <a class="header-anchor" href="#如何选择要装哪些包" aria-label="Permalink to &quot;如何选择要装哪些包&quot;">​</a></h2><ul><li>只想跑个 Web API？→ <code>Web.Api</code> + <code>Web.Docs</code>（依赖会自动带上 Core 等底层）</li><li>要读写数据库？→ 加 <code>Data</code></li><li>要缓存/认证/授权？→ 按需加 <code>Caching</code> / <code>Authentication</code> / <code>Authorization</code></li><li>不确定？→ 先看 <a href="./../quickstart">快速上手</a>，再回这里按需查阅</li></ul><p>大多数包无需单独安装——它们会作为上层包的 <code>[DependsOn]</code> 依赖被自动引入。</p><hr><h2 id="_1-公共与核心" tabindex="-1">1. 公共与核心 <a class="header-anchor" href="#_1-公共与核心" aria-label="Permalink to &quot;1. 公共与核心&quot;">​</a></h2><p>框架的地基，几乎所有上层模块都依赖它们。</p><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./utils">Utils</a></td><td>零依赖通用工具库：字符串、加密、异步、序列化、集合、反射、网络、文件 IO、数学、时间等</td></tr><tr><td><a href="./metadata">Metadata</a></td><td>框架元数据：名称、版本、作者、组织、支持平台等静态信息</td></tr><tr><td><a href="./core">Core</a></td><td>模块化引擎核心：<code>XiHanModule</code>、<code>[DependsOn]</code>、拓扑排序加载、生命周期钩子、DI 扩展、选项模式、异常处理</td></tr><tr><td><a href="./analyzers">Analyzers</a></td><td>Roslyn 代码分析器：编译期规范检查</td></tr></tbody></table><h2 id="_2-领域与应用" tabindex="-1">2. 领域与应用 <a class="header-anchor" href="#_2-领域与应用" aria-label="Permalink to &quot;2. 领域与应用&quot;">​</a></h2><p>DDD 分层与应用服务契约。</p><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./domain-shared">Domain.Shared</a></td><td>领域共享模型：基础实体类型、枚举、常量、值对象、异常</td></tr><tr><td><a href="./domain">Domain</a></td><td>DDD 领域层：聚合根、实体、领域服务、领域事件、规约、仓储抽象、业务规则引擎</td></tr><tr><td><a href="./application-contracts">Application.Contracts</a></td><td>应用服务契约：DTO 定义、应用服务接口</td></tr><tr><td><a href="./application">Application</a></td><td>应用层实现：应用服务基类、CRUD 基类、DTO 映射、动态 API 特性</td></tr></tbody></table><h2 id="_3-数据与持久化" tabindex="-1">3. 数据与持久化 <a class="header-anchor" href="#_3-数据与持久化" aria-label="Permalink to &quot;3. 数据与持久化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./data">Data</a></td><td>SqlSugar 数据访问：仓储模式、工作单元集成、多租户数据隔离、启动自动建表</td></tr><tr><td><a href="./uow">Uow</a></td><td>工作单元：AOP 拦截器自动管理事务边界</td></tr><tr><td><a href="./caching">Caching</a></td><td>混合缓存：HybridCache（内存 + Redis）、缓存拦截器、租户感知</td></tr></tbody></table><h2 id="_4-安全-·-认证-·-授权" tabindex="-1">4. 安全 · 认证 · 授权 <a class="header-anchor" href="#_4-安全-·-认证-·-授权" aria-label="Permalink to &quot;4. 安全 · 认证 · 授权&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./security">Security</a></td><td>安全与加密：BouncyCastle 企业级密码学、密钥管理、密码哈希、数据保护</td></tr><tr><td><a href="./authentication">Authentication</a></td><td>认证：JWT / OAuth2 / OIDC、令牌工厂、MFA、SSO</td></tr><tr><td><a href="./authorization">Authorization</a></td><td>授权：RBAC、策略授权、声明授权</td></tr></tbody></table><h2 id="_5-多租户-·-配置-·-校验" tabindex="-1">5. 多租户 · 配置 · 校验 <a class="header-anchor" href="#_5-多租户-·-配置-·-校验" aria-label="Permalink to &quot;5. 多租户 · 配置 · 校验&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./multitenancy-abstractions">MultiTenancy.Abstractions</a></td><td>多租户抽象：租户上下文接口、解析链</td></tr><tr><td><a href="./multitenancy">MultiTenancy</a></td><td>多租户：租户解析中间件、数据隔离、租户配置管理、生命周期</td></tr><tr><td><a href="./settings">Settings</a></td><td>设置管理：设置定义提供者模式、动态配置、多来源（租户级别）</td></tr><tr><td><a href="./validation-abstractions">Validation.Abstractions</a></td><td>校验抽象：校验异常与错误承载接口</td></tr><tr><td><a href="./validation">Validation</a></td><td>数据校验：当前为薄占位，核心类型在抽象包</td></tr></tbody></table><h2 id="_6-事件-·-消息-·-通信" tabindex="-1">6. 事件 · 消息 · 通信 <a class="header-anchor" href="#_6-事件-·-消息-·-通信" aria-label="Permalink to &quot;6. 事件 · 消息 · 通信&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./eventbus-abstractions">EventBus.Abstractions</a></td><td>事件总线抽象：发布/订阅接口、事件处理管道</td></tr><tr><td><a href="./eventbus">EventBus</a></td><td>事件总线：本地/分布式事件、Outbox 模式、事件存储</td></tr><tr><td><a href="./messaging">Messaging</a></td><td>消息处理：消息代理抽象（发布/消费/路由）</td></tr><tr><td><a href="./http">Http</a></td><td>HTTP 客户端：Polly 韧性策略（重试/熔断）、请求管道</td></tr></tbody></table><h2 id="_7-通用基础设施" tabindex="-1">7. 通用基础设施 <a class="header-anchor" href="#_7-通用基础设施" aria-label="Permalink to &quot;7. 通用基础设施&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./serialization">Serialization</a></td><td>序列化：System.Text.Json + Newtonsoft.Json 双引擎、策略管理</td></tr><tr><td><a href="./objectmapping">ObjectMapping</a></td><td>对象映射：Mapster 集成</td></tr><tr><td><a href="./localization-abstractions">Localization.Abstractions</a></td><td>国际化抽象：<code>IStringLocalizer</code> 抽象层</td></tr><tr><td><a href="./localization">Localization</a></td><td>国际化：多语言资源文件、动态文化切换</td></tr><tr><td><a href="./logging">Logging</a></td><td>结构化日志：Serilog 集成、文件/控制台输出、异步写入</td></tr><tr><td><a href="./castle">Castle</a></td><td>AOP 动态代理：Castle DynamicProxy 集成、服务拦截器注册</td></tr><tr><td><a href="./threading">Threading</a></td><td>并发辅助：取消令牌提供者、基于 AsyncLocal 的环境作用域</td></tr><tr><td><a href="./timing">Timing</a></td><td>时间策略：时区管理、时间抽象</td></tr><tr><td><a href="./distributed-ids">DistributedIds</a></td><td>分布式 ID：Snowflake / NanoId / SequentialGuid / Sqids 多方案</td></tr></tbody></table><h2 id="_8-存储-·-模板-·-任务-·-治理" tabindex="-1">8. 存储 · 模板 · 任务 · 治理 <a class="header-anchor" href="#_8-存储-·-模板-·-任务-·-治理" aria-label="Permalink to &quot;8. 存储 · 模板 · 任务 · 治理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./object-storage">ObjectStorage</a></td><td>对象存储：统一抽象 + 本地 / 阿里云 OSS / MinIO / 腾讯 COS 适配</td></tr><tr><td><a href="./virtual-file-system">VirtualFileSystem</a></td><td>虚拟文件系统：本地目录 + 程序集嵌入资源统一挂载、内存版本快照</td></tr><tr><td><a href="./templating">Templating</a></td><td>模板渲染：默认简单占位替换引擎 + 可选 Scriban、模板注册表</td></tr><tr><td><a href="./tasks">Tasks</a></td><td>定时任务：调度引擎（Cron/间隔/延迟）、后台服务基类、多租户感知</td></tr><tr><td><a href="./traffic">Traffic</a></td><td>流量治理：灰度路由（百分比/用户/租户/请求头）、限流与熔断策略接口</td></tr><tr><td><a href="./upgrade">Upgrade</a></td><td>升级引擎：版本存储、迁移执行、分布式锁、启动自动检查</td></tr><tr><td><a href="./script">Script</a></td><td>脚本引擎：基于 Roslyn 的 C# 动态脚本、编译校验与超时</td></tr><tr><td><a href="./search-engines">SearchEngines</a></td><td>搜索引擎：Elasticsearch 集成占位（预留依赖，尚未封装 API）</td></tr><tr><td><a href="./observability">Observability</a></td><td>可观测性：指标采集、性能监控、诊断（部分健康检查为占位）</td></tr><tr><td><a href="./devtools">DevTools</a></td><td>开发工具：自研命令行（CLI）框架，开发期辅助</td></tr></tbody></table><h2 id="_9-ai-与机器人" tabindex="-1">9. AI 与机器人 <a class="header-anchor" href="#_9-ai-与机器人" aria-label="Permalink to &quot;9. AI 与机器人&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./ai-abstractions">AI.Abstractions</a></td><td>AI 抽象：AI 服务接口与契约</td></tr><tr><td><a href="./ai">AI</a></td><td>AI 集成：LLM 接入（OpenAI 兼容）、智能代理、MCP 协议、RAG</td></tr><tr><td><a href="./bot">Bot</a></td><td>机器人核心：多平台消息接入的统一抽象</td></tr><tr><td><a href="./bot-email">Bot.Email</a></td><td>邮件通道：MailKit 集成</td></tr><tr><td><a href="./bot-sms">Bot.Sms</a></td><td>短信通道</td></tr><tr><td><a href="./bot-telegram">Bot.Telegram</a></td><td>Telegram 机器人</td></tr><tr><td><a href="./bot-dingtalk">Bot.DingTalk</a></td><td>钉钉机器人</td></tr><tr><td><a href="./bot-lark">Bot.Lark</a></td><td>飞书机器人</td></tr><tr><td><a href="./bot-wecom">Bot.WeCom</a></td><td>企业微信机器人</td></tr></tbody></table><h2 id="_10-web-层" tabindex="-1">10. Web 层 <a class="header-anchor" href="#_10-web-层" aria-label="Permalink to &quot;10. Web 层&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>说明</th></tr></thead><tbody><tr><td><a href="./web-core">Web.Core</a></td><td>Web 基础设施：托管环境、中间件管道、CORS、IP 地理定位（ip2region）、UA 解析</td></tr><tr><td><a href="./web-api">Web.Api</a></td><td>动态 API：自动 API 发现与注册、OpenAPI 安全、完整中间件管道</td></tr><tr><td><a href="./web-docs">Web.Docs</a></td><td>API 文档：Scalar UI + Swagger UI、动态 API 分组发现</td></tr><tr><td><a href="./web-gateway">Web.Gateway</a></td><td>API 网关：灰度路由（依赖 Traffic）、请求追踪、限流熔断</td></tr><tr><td><a href="./web-grpc">Web.Grpc</a></td><td>gRPC 服务集成</td></tr><tr><td><a href="./web-realtime">Web.RealTime</a></td><td>实时通信：SignalR 集成、JSON 序列化</td></tr></tbody></table><hr><h2 id="依赖关系速览" tabindex="-1">依赖关系速览 <a class="header-anchor" href="#依赖关系速览" aria-label="Permalink to &quot;依赖关系速览&quot;">​</a></h2><p>核心依赖链（从底层到上层）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Utils（零依赖）</span></span>
<span class="line"><span>  └ Metadata</span></span>
<span class="line"><span>      └ Core</span></span>
<span class="line"><span>          ├ Serialization</span></span>
<span class="line"><span>          ├ Security → Authentication → Authorization</span></span>
<span class="line"><span>          ├ Threading / Timing / DistributedIds</span></span>
<span class="line"><span>          ├ VirtualFileSystem → Localization</span></span>
<span class="line"><span>          ├ Uow → Caching(+Redis) / EventBus</span></span>
<span class="line"><span>          ├ Domain.Shared → Domain → Data(SqlSugar)</span></span>
<span class="line"><span>          │     └ Application.Contracts → Application</span></span>
<span class="line"><span>          ├ MultiTenancy.Abstractions → MultiTenancy → Tasks / Traffic / Upgrade</span></span>
<span class="line"><span>          ├ Http(+Polly) → AI(SemanticKernel + MCP) → Bot(MailKit + Telegram)</span></span>
<span class="line"><span>          └ Web.Core → Web.Api → Web.Docs / Web.Gateway / Web.Grpc / Web.RealTime</span></span></code></pre></div><blockquote><p>你只需在应用模块上 <code>[DependsOn]</code> 顶层包，整条依赖链会被框架自动装配。详见 <a href="./../concepts/modularity">核心概念 · 模块系统</a>。</p></blockquote>`,34)])])}const f=a(i,[["render",n]]);export{p as __pageData,f as default};
